// 1. Get timestamp base (approx 8 chars)
const timePart = Date.now().toString(36);

// 2. Get random base to fill the rest
const randomPart = Math.random().toString(36).substring(2);

// 3. Combine and trim to exactly 16 characters
const finalValue = (timePart + randomPart).substring(0, 16);

// 4. Return in strict n8n format
return [
  {
    json: {
      id: finalValue
    }
  }
];

